/* Encodage base64 d'une chaîne UTF-8 + repli MIME à 76 colonnes (documents Word .doc en MHTML) */
const b64utf8 = (str) => {
  const bytes = new TextEncoder().encode(str);
  let bin = "";
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin);
};
const mimeWrap = (b64) => b64.replace(/(.{76})/g, "$1\r\n");

/* QR rendu en tableau de cellules colorées : seul format fiable dans un document Word (.doc HTML) */
const qrTableHTML = (text, cell = 3) => {
  try {
    const { matrix, size } = qrMatrix(text);
    const q = 3; // zone de silence
    let rows = "";
    for (let r = -q; r < size + q; r++) {
      let tds = "";
      for (let c = -q; c < size + q; c++) {
        const noir = r >= 0 && r < size && c >= 0 && c < size && matrix[r][c];
        tds += `<td width="${cell}" height="${cell}" bgcolor="${noir ? "#000000" : "#FFFFFF"}" style="width:${cell}px;height:${cell}px;font-size:0;line-height:0;padding:0"></td>`;
      }
      rows += `<tr style="height:${cell}px">${tds}</tr>`;
    }
    return `<table cellspacing="0" cellpadding="0" border="0" style="border-collapse:collapse">${rows}</table>`;
  } catch (e) { return ""; }
};

/* Code d'authentification : empreinte des données de la carte + clé secrète de l'installation — voir @gestipers/shared */

const qrPayload = (e, secret, kind = "PR") => {
  const cfg = CARD_KINDS[kind] || CARD_KINDS.PR;
  return qrPayloadShared(e, secret, kind, cfg.ligne2(e));
};

const APP_ORIGIN = (
  typeof window !== "undefined" && window.location?.origin
    ? window.location.origin
    : (import.meta.env.VITE_APP_URL || "https://www.gestipers.org")
).replace(/\/$/, "");

const qrScanUrl = (mat, code) => qrScanUrlShared(APP_ORIGIN, mat, code);

const qrCardScanText = (e, secret, kind = "PR") => {
  try {
    return qrScanUrl(matricule(e, kind), authCode(e, secret, kind));
  } catch {
    return qrPayload(e, secret, kind);
  }
};

const PENDING_VERIFY_KEY = "ghr:pending-verify";
const readPendingVerify = () => {
  try { return sessionStorage.getItem(PENDING_VERIFY_KEY) || ""; } catch { return ""; }
};
const savePendingVerify = (raw) => {
  try { if (raw) sessionStorage.setItem(PENDING_VERIFY_KEY, raw); } catch { /* ignore */ }
};
const clearPendingVerify = () => {
  try { sessionStorage.removeItem(PENDING_VERIFY_KEY); } catch { /* ignore */ }
};

const QRSvg = ({ text, size = 64 }) => {
  const qr = useMemo(() => { try { return qrMatrix(text); } catch (e) { return null; } }, [text]);
  if (!qr) return null;
  const q = 2, dim = qr.size + q * 2;
  let d = "";
  for (let r = 0; r < qr.size; r++) for (let c = 0; c < qr.size; c++) if (qr.matrix[r][c]) d += `M${c + q} ${r + q}h1v1h-1z`;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${dim} ${dim}`} shapeRendering="crispEdges">
      <rect width={dim} height={dim} fill="#fff" />
      <path d={d} fill="#000" />
    </svg>
  );
};

